import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";import"./chunks/assets.C-ppGc-j.js";var i=JSON.parse(`{"title":"E区宿舍","description":"华南理工大学大学城校区E区宿舍概况","frontmatter":{"lang":"zh-CN","title":"E区宿舍","description":"华南理工大学大学城校区E区宿舍概况"},"headers":[],"relativePath":"infra/hemc/dorm-e.md","filePath":"infra/hemc/dorm-e.md","lastUpdated":1784905161000}`),a={name:`infra/hemc/dorm-e.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /infra/hemc/dorm-e.md for this page in Markdown format</div><h1 id="e区宿舍概况" tabindex="-1">E区宿舍概况 <a class="header-anchor" href="#e区宿舍概况" aria-label="Permalink to “E区宿舍概况”">​</a></h1><h2 id="_1-硬件" tabindex="-1">1. 硬件 <a class="header-anchor" href="#_1-硬件" aria-label="Permalink to “1. 硬件”">​</a></h2><h3 id="a-宿舍内部" tabindex="-1">a. 宿舍内部 <a class="header-anchor" href="#a-宿舍内部" aria-label="Permalink to “a. 宿舍内部”">​</a></h3><p>宿舍内部虽然不大，但是由于是新建的，设施都比较新。</p><p><img src="/assets/hemc/dorm_e_overview.jpg" alt="宿舍全景概览"></p><p><strong>基本规格：</strong></p><ul><li>宿舍普遍是 <strong>5m × 3.6m</strong> 的四人间</li><li>上床下桌，有自己的衣柜、书架和放行李的架子</li></ul><p><strong>书桌：</strong></p><p><img src="/assets/hemc/dorm_e_desk.jpg" alt="书桌与储物柜"></p><ul><li>规格：<strong>1.2m × 0.6m</strong></li><li>一侧与上床的楼梯相连，另一侧和衣柜相连</li><li>上方后部有书架，需要合理规划空间</li><li>书架底部与书桌高度差为 <strong>0.6m</strong></li></ul><p><strong>衣柜：</strong></p><ul><li>尺寸约为 <strong>0.8m × 0.6m × 1.15m</strong></li><li>下方还有一个宽长一样的储物柜：<strong>0.8m × 0.6m × 0.45m</strong></li><li>衣柜旁有四个开放柜（3个在上面的尺寸 <strong>0.3m × 0.25m × 0.33m</strong> + 一个最下面的 <strong>0.3m × 0.25m × 0.65m</strong>）</li></ul><p><strong>右侧储物：</strong></p><ul><li>可以放置生活用品和私人物品的抽屉和柜子</li><li>抽屉：<strong>0.4m × 0.33m × 0.1m</strong></li><li>柜子：<strong>0.6m × 0.33m × 0.45m</strong></li></ul><p><strong>书柜：</strong></p><ul><li>头上三个书柜，每个 <strong>0.4m × 0.2m</strong>（不封顶）</li></ul><p><strong>楼梯柜：</strong></p><ul><li>左/右侧是上床的楼梯，楼梯上有两个可储存柜子 <ul><li><strong>0.5m × 0.65m × 0.25m</strong></li><li><strong>0.5m × 0.4m × 0.25m</strong></li></ul></li><li>因为两个人共用一个楼梯，建议和室友商量使用</li></ul><p><strong>床铺：</strong></p><ul><li>尺寸：<strong>1.9m × 0.9m</strong></li><li>学校会自动加装护栏和挂蚊帐的架子</li></ul><h3 id="b-阳台及厕所浴室" tabindex="-1">b. 阳台及厕所浴室 <a class="header-anchor" href="#b-阳台及厕所浴室" aria-label="Permalink to “b. 阳台及厕所浴室”">​</a></h3><ul><li>阳台通常是 <strong>1.8m × 2.15m</strong>（某些宿舍的一角会被墙体占用）</li><li>有洗漱台、洗漱架</li><li>卫生间和浴室<strong>干湿分离</strong>，分别约为半个阳台大小</li><li>水费：<strong>3.75元/吨</strong></li><li>电费：<strong>0.6295元/度</strong></li></ul><p><img src="/assets/hemc/dorm_e_balcony.jpg" alt="阳台洗手台"></p><p><img src="/assets/hemc/dorm_e_bathroom.jpg" alt="浴室淋浴间"></p><p><img src="/assets/hemc/dorm_e_toilet.jpg" alt="卫生间"></p><hr><h2 id="_2-软件" tabindex="-1">2. 软件 <a class="header-anchor" href="#_2-软件" aria-label="Permalink to “2. 软件”">​</a></h2><ul><li>宿舍配备<strong>空调</strong>、<strong>风扇</strong></li><li><strong>饮水机</strong>在每层楼固定位置</li><li><strong>不熄灯不断电</strong>（会断校园网）</li><li>每栋楼应该是 <strong>7部电梯</strong></li><li><strong>e2/e3</strong> 有地下车库以及直达的楼梯（一部到车库的电梯）</li><li>楼下有<strong>自助售货机</strong>和<strong>外卖点</strong>（校内食堂外卖或者西亚超市的可以配送到这里）</li><li>每栋楼下有自己独特的<strong>功能室和活动室</strong>，例如： <ul><li><strong>e2</strong>：厨房、书法室</li><li><strong>e3</strong>：心理辅导室</li></ul></li></ul><hr><h2 id="_3-交通" tabindex="-1">3. 交通 <a class="header-anchor" href="#_3-交通" aria-label="Permalink to “3. 交通”">​</a></h2><p>E区确实离各个校内地方比较远，以下描述去学校一些重要地方的路径和时间（以 <strong>e3</strong> 为例，e2会近50m左右，e1会近100m左右）：</p><table tabindex="0"><thead><tr><th>目的地</th><th>距离/时间</th><th>备注</th></tr></thead><tbody><tr><td><strong>教学楼 a5~a1</strong></td><td>500m ~ 700m</td><td>由远到近；a1高楼尽量骑车，提前至少15分钟</td></tr><tr><td><strong>图书馆</strong></td><td>约800m</td><td>紧挨着a1</td></tr><tr><td><strong>教学区操场/体育馆</strong></td><td>约800~900+m</td><td>通勤约20分钟</td></tr><tr><td><strong>实验楼（b开头）</strong></td><td>15~25分钟</td><td>各栋楼不等</td></tr><tr><td><strong>快递点</strong></td><td>e3楼下 / 二饭旁</td><td>偶尔会有c10楼下的</td></tr><tr><td><strong>外卖（北门）</strong></td><td>约8分钟</td><td>拿取较为方便</td></tr><tr><td><strong>穗石</strong></td><td>约15分钟</td><td>附近美食和商圈</td></tr><tr><td><strong>三饭</strong></td><td>约15分钟</td><td></td></tr><tr><td><strong>二饭旁（瑞幸/遇见小面/麦当劳）</strong></td><td>约10分钟</td><td></td></tr><tr><td><strong>gogo新天地</strong></td><td>约25分钟</td><td></td></tr><tr><td><strong>南亭</strong></td><td>约30分钟</td><td></td></tr><tr><td><strong>北亭村</strong></td><td>约40分钟</td><td></td></tr><tr><td><strong>生物岛</strong></td><td>50分钟以上</td><td>建议不骑车</td></tr><tr><td><strong>地铁站（大学城站）</strong></td><td>约20分钟</td><td>从北门出发到d口；沿学校内部从西门出到f口</td></tr></tbody></table><blockquote><p><strong>Tip</strong>：从f口回e区骑车一路下坡比较爽！</p></blockquote><hr><h2 id="_4-忠告" tabindex="-1">4. 忠告 <a class="header-anchor" href="#_4-忠告" aria-label="Permalink to “4. 忠告”">​</a></h2><p>宿舍再好，重要的也是<strong>人</strong>。学会如何和你的室友相处，尽量让互相多一点包容，规划好责任。</p><p>希望你能在大学城e区度过快乐的住宿时光！</p>`,38)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};